struct Button {
    Rectangle bounds;
    const char* text;
    Color normalColor;
    Color hoverColor;
    Color pressedColor;
    bool isHovered;
    bool isPressed;
};

bool UpdateButton(Button& btn) {
    Vector2 mousePos = GetMousePosition();

    btn.isHovered = CheckCollisionPointRec(mousePos, btn.bounds);
    btn.isPressed = btn.isHovered && IsMouseButtonDown(MOUSE_LEFT_BUTTON);

    // إرجاع true عند الإفلات فوق الزر
    return btn.isHovered && IsMouseButtonReleased(MOUSE_LEFT_BUTTON);
}

void DrawButton(const Button& btn) {
    Color currentColor = btn.normalColor;

    if (btn.isPressed) {
        currentColor = btn.pressedColor;
    } else if (btn.isHovered) {
        currentColor = btn.hoverColor;
    }

    // رسم الخلفية مع زوايا مستديرة
    DrawRectangleRounded(btn.bounds, 0.3f, 8, currentColor);

    // إطار
    DrawRectangleRoundedLines(btn.bounds, 0.3f, 8, Color{255, 255, 255, 100});

    // النص في المنتصف
    int textWidth = MeasureText(btn.text, 20);
    Vector2 textPos = {
        btn.bounds.x + (btn.bounds.width - textWidth) / 2,
        btn.bounds.y + (btn.bounds.height - 20) / 2
    };
    DrawText(btn.text, textPos.x, textPos.y, 20, Color{255, 255, 255});
}

