struct Slider {
    Rectangle bounds;
    float* value;
    float minValue;
    float maxValue;
    const char* label;
    bool isDragging;
};

bool UpdateSlider(Slider& slider) {
    Vector2 mousePos = GetMousePosition();

    // مقبض السحب
    float handleWidth = 16;
    float trackWidth = slider.bounds.width - handleWidth;
    float normalizedValue = (*slider.value - slider.minValue) / (slider.maxValue - slider.minValue);
    Rectangle handleRect = {
        slider.bounds.x + normalizedValue * trackWidth,
        slider.bounds.y - 4,
        handleWidth,
        slider.bounds.height + 8
    };

    bool isHoveringHandle = CheckCollisionPointRec(mousePos, handleRect);
    bool isHoveringTrack = CheckCollisionPointRec(mousePos, slider.bounds);

    if (IsMouseButtonPressed(MOUSE_LEFT_BUTTON) && (isHoveringHandle || isHoveringTrack)) {
        slider.isDragging = true;
    }

    if (IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
        slider.isDragging = false;
    }

    if (slider.isDragging) {
        float relativeX = mousePos.x - slider.bounds.x;
        normalizedValue = Clamp(relativeX / trackWidth, 0.0f, 1.0f);
        *slider.value = slider.minValue + normalizedValue * (slider.maxValue - slider.minValue);
    }

    return slider.isDragging;
}

void DrawSlider(const Slider& slider) {
    float normalizedValue = (*slider.value - slider.minValue) / (slider.maxValue - slider.minValue);

    // مسار الخلفية
    DrawRectangleRounded(slider.bounds, 0.5f, 4, Color{60, 60, 60});

    // التعبئة
    Rectangle fillRect = {
        slider.bounds.x,
        slider.bounds.y,
        slider.bounds.width * normalizedValue,
        slider.bounds.height
    };
    DrawRectangleRounded(fillRect, 0.5f, 4, Color{100, 150, 200});

    // المقبض
    float handleX = slider.bounds.x + normalizedValue * (slider.bounds.width - 16);
    Rectangle handleRect = {handleX, slider.bounds.y - 4, 16, slider.bounds.height + 8};
    Color handleColor = slider.isDragging ? Color{150, 200, 255} : Color{200, 200, 200};
    DrawRectangleRounded(handleRect, 0.3f, 4, handleColor);

    // النص
    char valueText[32];
    sprintf(valueText, "%s: %.0f%%", slider.label, normalizedValue * 100);
    DrawText(valueText, slider.bounds.x, slider.bounds.y - 20, 14, Color{200, 200, 200});
}

struct Toggle {
    Rectangle bounds;
    bool* value;
    const char* label;
    bool isHovered;
    float animationProgress;  // للانيميشن
};

bool UpdateToggle(Toggle& toggle) {
    Vector2 mousePos = GetMousePosition();
    toggle.isHovered = CheckCollisionPointRec(mousePos, toggle.bounds);

    if (toggle.isHovered && IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
        *toggle.value = !(*toggle.value);
        return true;
    }

    // تحديث الانيميشن
    float targetProgress = *toggle.value ? 1.0f : 0.0f;
    toggle.animationProgress += (targetProgress - toggle.animationProgress) * 0.2f;

    return false;
}

void DrawToggle(const Toggle& toggle) {
    // الخلفية
    Color bgColor = *toggle.value ? Color{50, 150, 50} : Color{80, 80, 80};
    if (toggle.isHovered) {
        bgColor = *toggle.value ? Color{70, 180, 70} : Color{100, 100, 100};
    }
    DrawRectangleRounded(toggle.bounds, 0.5f, 8, bgColor);

    // المقبض الدائري
    float handleRadius = toggle.bounds.height / 2 - 4;
    float handleX = toggle.bounds.x + 4 + toggle.animationProgress * (toggle.bounds.width - 2 * handleRadius - 8);
    Vector2 handleCenter = {handleX + handleRadius, toggle.bounds.y + toggle.bounds.height / 2};
    DrawCircleV(handleCenter, handleRadius, Color{255, 255, 255});

    // الظل تحت المقبض
    DrawCircleV({handleCenter.x, handleCenter.y + 2}, handleRadius - 2, Color{200, 200, 200});

    // النص
    int textWidth = MeasureText(toggle.label, 14);
    DrawText(toggle.label, toggle.bounds.x - textWidth - 10,
             toggle.bounds.y + (toggle.bounds.height - 14) / 2, 14, Color{200, 200, 200});

    // حالة ON/OFF
    const char* stateText = *toggle.value ? "ON" : "OFF";
    DrawText(stateText, toggle.bounds.x + toggle.bounds.width + 10,
             toggle.bounds.y + (toggle.bounds.height - 12) / 2, 12,
             *toggle.value ? Color{100, 255, 100} : Color{150, 150, 150});
}

struct Dropdown {
    Rectangle bounds;
    const char** options;
    int optionCount;
    int* selectedIndex;
    bool isOpen;
    int hoveredIndex;
};

bool UpdateDropdown(Dropdown& dropdown) {
    Vector2 mousePos = GetMousePosition();

    if (CheckCollisionPointRec(mousePos, dropdown.bounds)) {
        if (IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
            dropdown.isOpen = !dropdown.isOpen;
        }
    } else if (dropdown.isOpen) {
        // التحقق من النقر على خيار
        for (int i = 0; i < dropdown.optionCount; i++) {
            Rectangle optionRect = {
                dropdown.bounds.x,
                dropdown.bounds.y + dropdown.bounds.height * (i + 1),
                dropdown.bounds.width,
                dropdown.bounds.height
            };
            if (CheckCollisionPointRec(mousePos, optionRect)) {
                dropdown.hoveredIndex = i;
                if (IsMouseButtonReleased(MOUSE_LEFT_BUTTON)) {
                    *dropdown.selectedIndex = i;
                    dropdown.isOpen = false;
                    return true;
                }
            }
        }

        // إغلاق عند النقر خارج القائمة
        if (IsMouseButtonPressed(MOUSE_LEFT_BUTTON)) {
            dropdown.isOpen = false;
        }
    }

    return false;
}

void DrawDropdown(const Dropdown& dropdown) {
    // الزر الرئيسي
    Color btnColor = dropdown.isOpen ? Color{70, 70, 70} : Color{50, 50, 50};
    DrawRectangleRounded(dropdown.bounds, 0.2f, 4, btnColor);
    DrawRectangleRoundedLines(dropdown.bounds, 0.2f, 4, Color{100, 100, 100});

    // النص المحدد
    DrawText(dropdown.options[*dropdown.selectedIndex],
             dropdown.bounds.x + 10, dropdown.bounds.y + 8, 14, Color{255, 255, 255});

    // سهم القائمة
    const char* arrow = dropdown.isOpen ? "▲" : "▼";
    DrawText(arrow, dropdown.bounds.x + dropdown.bounds.width - 20,
             dropdown.bounds.y + 8, 14, Color{200, 200, 200});

    // القائمة المنسدلة
    if (dropdown.isOpen) {
        for (int i = 0; i < dropdown.optionCount; i++) {
            Rectangle optionRect = {
                dropdown.bounds.x,
                dropdown.bounds.y + dropdown.bounds.height * (i + 1),
                dropdown.bounds.width,
                dropdown.bounds.height
            };

            Color optionColor = (i == dropdown.hoveredIndex) ? Color{70, 100, 70} : Color{40, 40, 40};
            DrawRectangleRec(optionRect, optionColor);

            Color textColor = (i == *dropdown.selectedIndex) ? Color{100, 255, 100} : Color{200, 200, 200};
            DrawText(dropdown.options[i], optionRect.x + 10, optionRect.y + 8, 14, textColor);
        }
    }
}

struct KeyBinding {
    const char* actionName;
    int* primaryKey;
    int* secondaryKey;
    bool isWaitingForInput;
    bool isWaitingForSecondary;
};

void UpdateKeyBinding(KeyBinding& binding) {
    if (binding.isWaitingForInput) {
        // التحقق من أي مفتاح مضغوط
        for (int key = 32; key < 350; key++) {
            if (IsKeyPressed(key)) {
                *binding.primaryKey = key;
                binding.isWaitingForInput = false;
                break;
            }
        }
        // إلغاء بالضغط على Escape
        if (IsKeyPressed(KEY_ESCAPE)) {
            binding.isWaitingForInput = false;
        }
    }
}

void DrawKeyBinding(KeyBinding& binding, Rectangle bounds) {
    Vector2 mousePos = GetMousePosition();
    bool isHovered = CheckCollisionPointRec(mousePos, bounds);

    // خلفية الصف
    Color bgColor = isHovered ? Color{50, 50, 60} : Color{35, 35, 45};
    DrawRectangleRec(bounds, bgColor);

    // اسم الإجراء
    DrawText(binding.actionName, bounds.x + 10, bounds.y + 10, 14, Color{200, 200, 200});

    // زر المفتاح الأساسي
    Rectangle primaryBtn = {bounds.x + bounds.width - 180, bounds.y + 5, 80, 30};
    Color primaryColor = binding.isWaitingForInput ? Color{100, 100, 50} : Color{60, 60, 70};
    DrawRectangleRec(primaryBtn, primaryColor);
    DrawRectangleLinesEx(primaryBtn, 1, Color{100, 100, 100});

    const char* primaryText = binding.isWaitingForInput ? "..." : GetKeyName(*binding.primaryKey);
    int textWidth = MeasureText(primaryText, 12);
    DrawText(primaryText, primaryBtn.x + (80 - textWidth)/2, primaryBtn.y + 9, 12, Color{255, 255, 255});

    // التفاعل
    if (IsMouseButtonReleased(MOUSE_LEFT_BUTTON) && CheckCollisionPointRec(mousePos, primaryBtn)) {
        binding.isWaitingForInput = true;
    }
}

const char* GetKeyName(int key) {
    static char name[16];
    switch(key) {
        case KEY_SPACE: return "Space";
        case KEY_LEFT_SHIFT: return "L-Shift";
        case KEY_LEFT_CONTROL: return "L-Ctrl";
        case KEY_ENTER: return "Enter";
        default:
            sprintf(name, "%c", (char)key);
            return name;
    }
}
